function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // Use bitmask to represent visited nodes
    const maxMask = 1 << n;

    // DFS to find the longest palindromic path
    let maxLength = 0;

    function dfs(node: number, visited: number, path: string[]): void {
        // Update the maximum length if current path is a palindrome
        if (isPalindrome(path)) {
            maxLength = Math.max(maxLength, path.length);
        }

        // Try to visit all adjacent nodes
        for (const neighbor of adj[node]) {
            if (!(visited & (1 << neighbor))) {
                path.push(label[neighbor]);
                dfs(neighbor, visited | (1 << neighbor), path);
                path.pop();
            }
        }
    }

    // Try all starting nodes
    for (let i = 0; i < n; i++) {
        const path: string[] = [label[i]];
        dfs(i, 1 << i, path);
