from typing import List

def solve(n: int, edges: List[List[int]], label: str) -> int:
    # Build adjacency list
    adj = [[] for _ in range(n)]
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    max_length = 0

    def is_palindrome(path: List[str]) -> bool:
        left, right = 0, len(path) - 1
        while left < right:
            if path[left] != path[right]:
                return False
            left += 1
            right -= 1
        return True

    def dfs(node: int, visited: int, path: List[str]) -> None:
        nonlocal max_length
        if is_palindrome(path):
            max_length = max(max_length, len(path))

        for neighbor in adj[node]:
            if not (visited & (1 << neighbor)):
                path.append(label[neighbor])
                dfs(neighbor, visited | (1 << neighbor), path)
                path.pop()

    for start in range(n):
        path = [label[start]]
        dfs(start, 1 << start, path)

    return max_length
